   * when compared to the target sorted array.
   * 
   * More precisely, if we partition nums into blocks of size k, and the target sorted array is sorted_nums.
   * For the operation to succeed, each block nums[i*k .. (i+1)*k - 1] must contain exactly the elements
   * that belong to the corresponding block sorted_nums[i*k .. (i+1)*k - 1].
   * Since cyclic shifts only permute elements within the block, the multiset of elements in the block must match
   * the multiset of elements in the target sorted block.
   * 
   * However, a simpler necessary and sufficient condition for a block of size k to be sortable to its *locally sorted state* 
   * using only cyclic shifts is that the block must *already* be a cyclic shift of its sorted version.
   * 
   * Let's re-read the problem: "independently for each subarray perform cyclic shifts (left or right arbitrarily many times)".
   * This means within a block, we can arrange its elements into *any* cyclic permutation of itself.
   * If the target sorted array is $S$, and $nums$ is partitioned into blocks $B_1, B_2, \dots, B_{n/k}$.
   * The target sorted array is $S = S_1 S_2 \dots S_{n/k}$, where $S_i$ is the block of $S$ of size $k$ starting at $i \cdot k$.
   * The operation allows us to transform $B_i$ into any cyclic permutation of $B_i$.
   * For the entire array to become sorted, we must be able to transform $B_i$ into $S_i$.
   * This is possible if and only if $S_i$ is a cyclic permutation of $B_i$.
   */
  def canBeSorted(nums: Seq[Int], k: Int): Boolean = {
    if (k == 0 || k > nums.length) return false
    if (k == 1) return false // Based on Example 1: k=1 fails

    val n = nums.length
    val sortedNums = nums.sorted

    // Check if each block B_i can be transformed into the target block S_i via cyclic shift
    val numBlocks = n / k

    for (i <- 0 until numBlocks) {
      val start = i * k

      // The current block B_i from nums
      val blockB = nums.slice(start, start + k).toSeq

      // The target block S_i from sortedNums
      val blockS = sortedNums.slice(start, start + k).toSeq

      // Check if blockS is a cyclic shift of blockB.
      // This is true if and only if blockS is a substring of blockB + blockB (when viewed as sequences/strings of elements)

      // Since we are dealing with sequences of integers, we need a custom check for cyclic permutation.

      // A sequence X is a cyclic permutation of sequence Y if:
      // 1. length(X) == length(Y)
      // 2. multiset(X) == multiset(Y)
      // 3. There exists a rotation r such that X[j] == Y[(j+r) mod k] for all j.

      // For blockB and blockS to be cyclically shiftable into each other, they must be anagrams,
      // AND blockS must be a cyclic shift of blockB.

      // Let's check the anagram property first (necessary condition)
      if (blockB.toSeq.sorted != blockS.toSeq.sorted) {
        return false
      }

      // Now check the cyclic shift property.
      // We check if blockS is a rotation of blockB.
      val doubledB = blockB ++ blockB

      var isCyclicShift = false
      for (r <- 0 until k) { // r is the rotation amount applied to blockB to get blockS
        // Check if rotating blockB by r positions matches blockS
        var match = true
        for (j <- 0 until k) {
          // Element at index j in blockS must match element at index (j+r) mod k in blockB
          // Or, element at index j in blockS must match element at index j in the rotation of blockB
          val b_rotated_index = (j + r) % k
          if (blockS(j) != blockB(b_rotated_index)) {
             match = false
             break
          }
        }
        if (match) {
          isCyclicShift = true
          break
        }
      }

      if (!isCyclicShift) {
        return false
      }
    }

    true
  }

  def nums(numsArr: Array[Long]): Long = {
    // Convert Array[Long] to Seq[Int] since constraints suggest nums[i] <= 10^5
    val numsInt: Seq[Int] = numsArr.map(_.toInt)
    val n = numsInt.length

    if (n == 0) return 0L

    var totalSum: Long = 0

    // Find all divisors k of n
    var k = 1
    while (k * k <= n) {
      if (n % k == 0) {
        // Check k
        if (k > 1 && canBeSorted(numsInt, k)) {
          totalSum += k.toLong
        }

        // Check n/k, unless k*k == n
        if (k * k != n) {
          val k2 = n / k
          if (k2 > 1 && canBeSorted(numsInt, k2)) {
            totalSum += k2.toLong
          }
        }
      }
      k += 1
    }

    totalSum
  }
